__kernel void
nw_kernel1(  __global int* referrence,
			  __global int* matrix_cuda, 
              __global int* output_buffer,
			  __local int* temp,
              __local int* ref,
			  int cols,
			  int penalty,
			  int i,
			  int block_width,
              int worksize,
              int offset_r,
              int offset_c) 
{
  int bx = get_global_id(0) / BLOCK_SIZE;
  int tx = get_local_id(0);

  int b_index_x = bx;
  int b_index_y = i - 1 - bx;

  int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
  int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
  int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
  int index_nw =  cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

  int temp_idx = tx * (BLOCK_SIZE + 1);
  int ref_idx = tx * BLOCK_SIZE;

   if (tx == 0)
		  temp[temp_idx + 0] = matrix_cuda[index_nw];


  for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
  ref[ref_idx + ty] = referrence[index + cols * ty];

  barrier(CLK_LOCAL_MEM_FENCE);

  temp[temp_idx + tx + 1] = matrix_cuda[index_w + cols * tx];

  barrier(CLK_LOCAL_MEM_FENCE);

  temp[0 * (BLOCK_SIZE + 1) + tx + 1] = matrix_cuda[index_n];

  barrier(CLK_LOCAL_MEM_FENCE);


  for( int m = 0 ; m < BLOCK_SIZE ; m++){

	  if ( tx <= m ){

		  int t_index_x =  tx + 1;
		  int t_index_y =  m - tx + 1;

          temp[temp_idx + t_index_x + t_index_y * (BLOCK_SIZE + 1)] = maximum( temp[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x-1] + ref[(t_index_y-1)*BLOCK_SIZE + t_index_x-1],
		                                        temp[temp_idx + t_index_x + (t_index_y-1)*(BLOCK_SIZE+1)]  - penalty, 
												temp[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x]  - penalty);



	  }

	  barrier(CLK_LOCAL_MEM_FENCE);

    }

 for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){

	  if ( tx <= m){

		  int t_index_x =  tx + BLOCK_SIZE - m ;
		  int t_index_y =  BLOCK_SIZE - tx;

          temp[temp_idx + t_index_x + t_index_y * (BLOCK_SIZE + 1)] = maximum( temp[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x-1] + ref[(t_index_y-1)*BLOCK_SIZE + t_index_x-1],
		                                        temp[temp_idx + t_index_x + (t_index_y-1)*(BLOCK_SIZE+1)]  - penalty, 
												temp[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x]  - penalty);

	  }

	  barrier(CLK_LOCAL_MEM_FENCE);
  }

  for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
  output_buffer[index + ty * cols] = temp[temp_idx + tx + 1 + (ty+1)*(BLOCK_SIZE+1)];

}


